arguments.file_text:
@code {
    private int _currentStep = 1;
    private Order _order = new();

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _currentStep = 2;
    }

    private void GoBackToShipping()
    {
        _currentStep = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

<div class="checkout-wizard">
    <h2>Checkout — Step @_currentStep of 2</h2>

    @if (_currentStep == 1)
    {
        <ShippingStep Shipping="_order.Shipping"
                      OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="GoBackToShipping"
                     OnPlaceOrder="PlaceOrder" />
    }
</div>

@implements IDisposable
@inject IAddressValidator AddressValidator

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation before starting a new one.
        CancelPendingValidation();

        _validationError = null;
        _isValidating = true;

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" @bind="Shipping.Name" disabled="@_isValidating" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" disabled="@_isValidating" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" disabled="@_isValidating" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" disabled="@_isValidating" />
    </div>

    @if (!string.IsNullOrEmpty(_validationError))
    {
        <div class="validation-error">@_validationError</div>
    }

    <button @onclick="ValidateAndProceed" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner"></span> @:Validating…
        }
        else
        {
            @:Next
        }
    </button>
</div>

